import{_ as e,o as a,c as t,d as r}from"./app.51ce790e.js";const u='{"title":"\u0424\u0420\u0423\u041A\u0422","description":"","frontmatter":{"title":"\u0424\u0420\u0423\u041A\u0422","date":"2022-02-16T00:00:00.000Z","cover":"sq-round.svg","subtitle":"\u0424\u043E\u043D\u0434 \u0420\u0430\u0437\u0432\u0438\u0442\u0438\u044F \u0423\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \u041A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 \u0438 \u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430"},"headers":[],"relativePath":"frukt/index.md"}',o={},s=r('<p><a href="./foundation/">\u0424\u043E\u043D\u0434</a> - \u043D\u0435\u043A\u043E\u043C\u043C\u0435\u0440\u0447\u0435\u0441\u043A\u0430\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044F, \u0432\u0441\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u044B \u043A\u043E\u0442\u043E\u0440\u043E\u0439 \u0434\u043E\u0431\u0440\u043E\u0432\u043E\u043B\u044C\u043D\u043E \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043D\u0430 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E \u0435\u0451 \u043C\u0438\u0441\u0441\u0438\u0438.</p><p><a href="./mission/">\u041C\u0438\u0441\u0441\u0438\u044F</a> \u0424\u0420\u0423\u041A\u0422\u0430 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 <a href="./development/">\u0440\u0430\u0437\u0432\u0438\u0442\u0438\u0438</a> <a href="./universalization/">\u0423\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438</a>, <a href="./cooperation/">\u041A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438</a> \u0438 <a href="./creativity/">\u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u0430</a> \u0432 \u0436\u0438\u0437\u043D\u0438 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0445 \u043B\u044E\u0434\u0435\u0439, \u043A\u043E\u043B\u043B\u0435\u043A\u0442\u0438\u0432\u043E\u0432 \u0438 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u0432 \u0446\u0435\u043B\u043E\u043C.</p><p>\u0421\u0442\u0430\u0442\u044C \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u043E\u043C \u0424\u043E\u043D\u0434\u0430 \u0424\u0420\u0423\u041A\u0422 \u043C\u043E\u0436\u0435\u0442 \u043A\u0430\u0436\u0434\u044B\u0439 - \u043C\u043E\u0436\u0435\u0442\u0435 \u043D\u0430\u0447\u0430\u0442\u044C \u043F\u0440\u044F\u043C\u043E \u0441 \u0441\u0435\u0431\u044F. \u041F\u043E\u043F\u0440\u043E\u0431\u0443\u0439\u0442\u0435 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u044C \u0432 \u0441\u0435\u0431\u0435 \u0438 \u0441\u0432\u043E\u0435\u0439 \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u043E\u0441\u0442\u0438 \u043E\u0431\u0449\u0435\u0435 \u0442\u0435\u0447\u0435\u043D\u0438\u0435 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u044B \u0438 \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u043A \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u044F\u043C <a href="./../research/from/">\u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0446\u0438\u0438 \u0438 \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u044F</a>. \u0415\u0441\u043B\u0438 \u0432\u044B \u0434\u0430\u0432\u043D\u043E \u0443\u0436\u0435 \u043E\u0449\u0443\u0449\u0430\u0435\u0442\u0435 \u0442\u0430\u043A\u043E\u0435 \u0432\u0441\u0435\u043E\u0431\u0449\u0435\u0435 \u0441\u0442\u0440\u0435\u043C\u043B\u0435\u043D\u0438\u0435, \u0442\u043E \u0432\u043F\u043E\u043B\u043D\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0434\u0430\u0436\u0435 \u0443\u0441\u043F\u0435\u043B\u0438 \u0434\u0430\u043B\u0435\u043A\u043E \u0432 \u044D\u0442\u043E\u043C \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044C\u0441\u044F. \u0418, \u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E,\xA0\u0434\u0430\u0436\u0435 \u043D\u0435 \u0437\u0430\u0434\u0443\u043C\u044B\u0432\u0430\u043B\u0438\u0441\u044C, \u0447\u0442\u043E \u0438 \u0432 \u0434\u0440\u0443\u0433\u0438\u0445 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u0445 \u043C\u043E\u0436\u0435\u0442 \u0436\u0434\u0430\u0442\u044C \u0435\u0449\u0435 \u0431\u043E\u043B\u044C\u0448\u0438\u0439, \u0438\u0441\u043A\u043B\u044E\u0447\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0412\u0430\u0448 \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u0443\u0441\u043F\u0435\u0445. \u0412\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0441\u0430\u043C\u0438 \u0432\u044B\u0431\u0438\u0440\u0430\u0442\u044C \u0441\u0432\u043E\u0438 \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u0438\u044F \u0438 \u0438\u0434\u0435\u0430\u043B\u044B \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u044C \u0438\u043C \u0441\u0430\u043C\u043E\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u043D\u043E \u0438 \u0441 \u0440\u0430\u0434\u043E\u0441\u0442\u044C\u044E.</p><p>\u0422\u0443\u0442 \u043F\u0435\u0440\u0435\u0434 \u043A\u0430\u0436\u0434\u044B\u043C \u0432\u0441\u0442\u0430\u0435\u0442 \u043A\u043E\u043B\u043E\u0441\u0441\u0430\u043B\u044C\u043D\u044B\u0439 \u0432\u043E\u043F\u0440\u043E\u0441 \u0432\u044B\u0431\u043E\u0440\u0430 \u0434\u043E\u0441\u0442\u043E\u0439\u043D\u044B\u0445 \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0435\u0439 \u0438 \u0438\u0434\u0435\u0430\u043B\u043E\u0432 \u0438 \u043F\u0440\u0438\u043D\u044F\u0442\u0438\u044F \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0437\u0430 \u044D\u0442\u043E\u0442 \u0432\u044B\u0431\u043E\u0440. \u042D\u0442\u043E \u043F\u0443\u0442\u044C \u0444\u0438\u043B\u043E\u0441\u043E\u0444\u0438\u0438, \u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u0430\u043C\u043E\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u043F\u0435\u0440\u0435\u043E\u0441\u043C\u044B\u0441\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0433\u043E \u043E\u043F\u044B\u0442\u0430 \u0447\u0435\u043B\u043E\u0432\u0435\u0447\u0435\u0441\u0442\u0432\u0430. \u041A\u0430\u0436\u0434\u044B\u0439 \u0438\u0434\u0443\u0449\u0438\u0439 \u043F\u043E \u044D\u0442\u043E\u043C\u0443 \u043F\u0443\u0442\u0438 \u043D\u0430\u0439\u0434\u0435\u0442 \u0441\u0432\u043E\u0438 \u043E\u0442\u0432\u0435\u0442\u044B. \u041D\u043E \u0432\u0430\u0436\u043D\u043E \u0435\u0449\u0435 \u0438 \u0434\u0435\u043B\u0438\u0442\u044C\u0441\u044F \u0441 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u043C\u0438 \u0442\u0435\u043C, \u0447\u0442\u043E \u043A\u0430\u0436\u0434\u044B\u0439 \u0438\u0437 \u043D\u0430\u0441 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u043B \u0438 \u043F\u043E\u043B\u044E\u0431\u0438\u043B. \u041F\u0440\u0438\u0433\u043B\u0430\u0448\u0430\u0442\u044C \u0434\u0440\u0443\u0433\u0438\u0445 \u043F\u0440\u0438\u0441\u043E\u0435\u0434\u0438\u043D\u0438\u0442\u044C\u0441\u044F \u043A \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043E\u0431\u0449\u0435\u043F\u043E\u043B\u0435\u0437\u043D\u044B\u0445 \u0446\u0435\u043B\u0435\u0439 - \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431 \u043D\u0430\u0439\u0442\u0438 \u0434\u0440\u0443\u0437\u0435\u0439 \u0438 \u0432\u0441\u0435 \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u044B\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u044B, \u0447\u0442\u043E\u0431\u044B \u0432\u043C\u0435\u0441\u0442\u0435 \u0440\u0435\u0430\u043B\u0438\u0437\u043E\u0432\u044B\u0432\u0430\u0442\u044C \u043F\u0440\u043E\u0435\u043A\u0442\u044B. \u041F\u0440\u043E\u0435\u043A\u0442\u043D\u044B\u0439 \u043F\u043E\u0434\u0445\u043E\u0434 \u0437\u0430\u0434\u0430\u0435\u0442 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0443 \u0440\u0435\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438 \u043B\u044E\u0431\u044B\u0445 \u0438\u0434\u0435\u0439.</p><p>\u0412 \u0431\u0435\u0441\u043A\u0440\u0430\u0439\u043D\u0435\u043C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0439 \u043C\u044B\u0441\u043B\u0438 \u043C\u044B \u0438\u0449\u0435\u043C \u0438\u0434\u0435\u0438, \u0432\u0435\u0434\u0443\u0449\u0438\u0435 \u0432 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0438 \u043D\u0430\u0448\u0438\u0445 \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0435\u0439. \u0412 \u044D\u0442\u043E\u043C \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u0442 <a href="./ukt/">\u0440\u0435\u0439\u0442\u0438\u043D\u0433 \u0423\u041A\u0422</a> \u2013 \u0443\u043A\u0430\u0437\u0430\u0442\u0435\u043B\u044C \u043D\u0430 \u043F\u0440\u043E\u0442\u0438\u0432\u043E\u043F\u043E\u043B\u043E\u0436\u043D\u044B\u0439 \u043F\u043E\u043B\u044E\u0441 \u043E\u0442 \u0431\u0430\u0437\u043E\u0432\u044B\u0445 \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0435\u0439 \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u043A \u0438\u0445 \u0430\u043D\u0442\u0438\u0442\u0435\u0437\u0430\u043C. \u041D\u043E \u044D\u0442\u043E \u043D\u0435 \u043F\u0440\u043E\u0441\u0442\u043E \u043E\u0442\u0440\u0438\u0446\u0430\u043D\u0438\u0435, \u044D\u0442\u043E \u0444\u043E\u0440\u043C\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0430\u0442\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E\u0435 \u0446\u0435\u043B\u0435\u043F\u043E\u043B\u0430\u0433\u0430\u043D\u0438\u0435.</p><p>\u0422\u0440\u0438 \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0424\u043E\u043D\u0434\u0430 - <a href="./../research/to/">\u0423\u043D\u0438\u0432\u0435\u0440\u0441\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044F, \u041A\u043E\u043E\u043F\u0435\u0440\u0430\u0446\u0438\u044F \u0438 \u0422\u0432\u043E\u0440\u0447\u0435\u0441\u0442\u0432\u043E</a> \u0437\u0430\u0434\u0430\u044E\u0442 \u0442\u0440\u0438 \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0430\u0442\u043D\u044B\u0435 \u043E\u0441\u0438, \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u044E\u0449\u0438\u0435 \u043E\u0440\u0438\u0435\u043D\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u0438 \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u043D\u043E \u0434\u0432\u0438\u0433\u0430\u0442\u044C\u0441\u044F \u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u043A\u0443\u043B\u044C\u0442\u0443\u0440\u043D\u044B\u0445 \u0446\u0435\u043D\u043D\u043E\u0441\u0442\u0435\u0439. \u0412\u043E\u0437\u044C\u043C\u0435\u043C \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442 \u043A\u0430\u043A \u0442\u043E\u0447\u043A\u0443 \u043D\u0443\u043B\u044F \u0438 \u0432 \u043E\u0442\u0440\u0438\u0446\u0430\u0442\u0435\u043B\u044C\u043D\u0443\u044E \u0441\u0442\u043E\u0440\u043E\u043D\u0443 \u043E\u0442\u043B\u043E\u0436\u0438\u043C \u043E\u0441\u0438 \u0442\u0440\u0435\u0445 \u043F\u0435\u0440\u0435\u043D\u0430\u0441\u044B\u0449\u0435\u043D\u043D\u044B\u0445 \u0438\u0434\u0435\u0438 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u0438, \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0446\u0438\u0438 \u0438 \u043F\u043E\u0442\u0440\u0435\u0431\u043B\u0435\u043D\u0438\u044F. \u0422\u0430\u043C \u043C\u043E\u0436\u043D\u043E \u0440\u0430\u0437\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u043F\u043E\u0447\u0442\u0438 \u0432\u0441\u044E \u043F\u043E\u0432\u0441\u0435\u0434\u043D\u0435\u0432\u043D\u043E\u0441\u0442\u044C \u0441\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0433\u043E \u0433\u043E\u0440\u043E\u0436\u0430\u043D\u0438\u043D\u0430. \u041D\u043E \u0442\u0435\u043F\u0435\u0440\u044C \u043C\u044B \u043C\u043E\u0436\u0435\u043C \u0441\u043C\u043E\u0442\u0440\u0435\u0442\u044C \u0448\u0438\u0440\u0435! \u0412 \u043F\u043E\u043B\u043E\u0436\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043D\u0430\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F\u0445 \u0443 \u043D\u0430\u0441 \u0442\u0435\u043F\u0435\u0440\u044C \u0435\u0441\u0442\u044C \u0442\u0440\u0435\u0445\u043C\u0435\u0440\u043D\u043E\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u043A \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044F\u043C, \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u044B\u043C \u0443\u0440\u0430\u0432\u043D\u043E\u0432\u0435\u0441\u0438\u0442\u044C \u043D\u0430\u0441 \u0438 \u043E\u043A\u0440\u0443\u0436\u0430\u044E\u0449\u0438\u0439 \u043C\u0438\u0440.</p>',6),_=[s];function n(i,p,c,f,d,h){return a(),t("div",null,_)}var m=e(o,[["render",n]]);export{u as __pageData,m as default};
